mapper.select:
SELECT a.order_no AS orderNo, a.coin_from AS coinFrom, a.coin_amount AS coinAmount, a.coin_to AS coinTo, a.created_time as coinTime, a.wallet_type AS walletType, a.agent_account AS agentAccount, a.balance_type AS balanceType, a.business_coin_type AS businessCoinType, a.coin_type AS coinType, a.remark AS remark, "1" AS status, b.deposit_withdraw_address AS depositWithdrawAddress, IF(a.business_coin_type = '2',c.agent_account,'') AS transferOutAccount, IF(a.business_coin_type = '2',c.transfer_account,'') AS transferInAccount, b.deposit_withdraw_type_code AS depositWithdrawTypeCode FROM agent_coin_record a LEFT JOIN agent_deposit_withdrawal b on b.order_no = a.order_no LEFT JOIN agent_transfer_record c on c.order_no = a.order_no where balance_type in ('1','2')
AND a.agent_id = #{vo.agentId}
AND a.wallet_type = #{vo.walletType}
AND a.coin_type in
#{value}
AND a.created_time >= #{vo.startTime}
AND a.created_time <= #{vo.endTime}
order by a.created_time desc

SELECT a.order_no AS orderNo, a.coin_amount AS coinAmount, a.coin_to AS coinToAmount, a.created_time as coinTime, a.wallet_type AS walletType, a.agent_account AS agentAccount, a.balance_type AS balanceType, a.business_coin_type AS businessCoinType, a.coin_type AS coinType, a.remark AS remark, "1" AS status, b.deposit_withdraw_address AS depositWithdrawAddress, c.agent_account AS transferOutAccount, c.transfer_account AS transferInAccount FROM agent_coin_record a LEFT JOIN agent_deposit_withdrawal b on b.order_no = a.order_no LEFT JOIN agent_transfer_record c on c.order_no = a.order_no WHERE a.order_no = #{vo.orderNo}
AND a.wallet_type = #{vo.walletType}
AND a.balance_type = #{vo.balanceType}
